sysevent_script_action.script:
// This runs asynchronously in the background when the event fires!

// THE FIX: We must force ServiceNow to convert the Java objects to JS Strings
var tableName = String(event.parm1); 
var sysIdsStr = String(event.parm2);
var jobSysId  = String(event.instance);

var exporter = new x_1862238_tracenow.dm_export(); 

// Now this strict equality will work perfectly!
if (tableName === 'mixed_payload') {
    exporter.exportMixedToAttachment(sysIdsStr, jobSysId);
} else {
    exporter.exportToAttachment(tableName, sysIdsStr, jobSysId);
}
